INSERT INTO `fitness_plan` VALUES (6, '\"{\\\"oneDay\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"燕麦50g + 蛋白3个 + 全蛋1个 + 蓝莓50g + 无糖杏仁奶200ml\\\", \\\"noon\\\": \\\"鸡胸肉150g + 糙米饭90g（熟重）+ 西兰花200g + 橄榄油5g\\\", \\\"late\\\": \\\"三文鱼120g + 菠菜沙拉（生菠菜150g + 小番茄5颗 + 黄瓜半根 + 油醋汁5ml）\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"力量训练（上肢推：胸、肩、三头）\\\", \\\"action\\\": [\\\"平板杠铃卧推 4组×8-10次\\\", \\\"哑铃肩推 4组×10次\\\", \\\"上斜哑铃卧推 3组×10-12次\\\", \\\"绳索下压 3组×12-15次\\\", \\\"侧平举 3组×15次\\\"], \\\"aerobic\\\": \\\"空腹低强度快走30分钟（可选）\\\", \\\"duration\\\": \\\"60-70分钟\\\"}}, \\\"towDay\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"全麦吐司2片 + 牛油果1/4个 + 水煮蛋2个 + 黑咖啡\\\", \\\"noon\\\": \\\"瘦牛肉150g + 红薯140g（熟重）+ 混合蔬菜（生菜、彩椒、洋葱）200g + 橄榄油5g\\\", \\\"late\\\": \\\"虾仁120g + 芦笋200g + 藜麦45g（干重）\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"力量训练（下肢：股四头肌、腘绳肌、臀）+ 有氧\\\", \\\"action\\\": [\\\"杠铃深蹲 4组×8-10次\\\", \\\"罗马尼亚硬拉 4组×10次\\\", \\\"保加利亚分腿蹲 3组×10次/腿\\\", \\\"腿弯举 3组×12-15次\\\", \\\"提踵 4组×15-20次\\\"], \\\"aerobic\\\": \\\"高强度间歇训练（HIIT）20分钟（如：30秒冲刺+60秒慢走，重复8轮）\\\", \\\"duration\\\": \\\"70-80分钟\\\"}}, \\\"threeDay\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"希腊酸奶150g（无糖）+ 奇亚籽10g + 草莓50g + 蛋白粉1勺（加水）\\\", \\\"noon\\\": \\\"鸡腿肉（去皮）150g + 荞麦面55g（干重）+ 青菜200g + 蒜蓉橄榄油5g\\\", \\\"late\\\": \\\"豆腐150g + 海带汤 + 紫甘蓝沙拉100g + 杏仁10颗\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"主动恢复日\\\", \\\"action\\\": [\\\"快走或骑行40分钟 + 泡沫轴放松 + 拉伸\\\"], \\\"aerobic\\\": \\\"\\\", \\\"duration\\\": \\\"45-50分钟\\\"}}, \\\"fourDay\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"燕麦40g + 蛋白3个 + 核桃10g + 苹果半个\\\", \\\"noon\\\": \\\"金枪鱼罐头（水浸）120g + 全麦意面55g（干重）+ 西葫芦炒蘑菇150g + 橄榄油5g\\\", \\\"late\\\": \\\"鸡胸肉120g + 烤彩椒+西兰花200g + 南瓜100g（熟重）\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"力量训练（上肢拉：背、二头）\\\", \\\"action\\\": [\\\"引体向上（辅助）4组×力竭\\\", \\\"杠铃划船 4组×8-10次\\\", \\\"高位下拉 3组×10-12次\\\", \\\"坐姿划船 3组×12次\\\", \\\"哑铃弯举 3组×12-15次\\\"], \\\"aerobic\\\": \\\"空腹低强度快走30分钟（可选）\\\", \\\"duration\\\": \\\"60-70分钟\\\"}}, \\\"fiveDay\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"全麦贝果1个 + 花生酱10g + 水煮蛋2个 + 黑咖啡\\\", \\\"noon\\\": \\\"瘦猪肉150g + 糙米饭90g（熟重）+ 芥蓝200g + 蒜蓉橄榄油5g\\\", \\\"late\\\": \\\"鳕鱼120g + 芽菜沙拉150g + 小番茄+黄瓜 + 柠檬橄榄油汁\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"全身功能性训练 + 有氧\\\", \\\"action\\\": [\\\"壶铃摇摆 4组×20次\\\", \\\"战绳 3组×30秒\\\", \\\"跳箱 3组×10次\\\", \\\"农夫行走 3组×30米\\\", \\\"平板支撑 3组×45秒\\\"], \\\"aerobic\\\": \\\"中等强度稳态有氧（如跑步机快走/慢跑）30分钟\\\", \\\"duration\\\": \\\"60分钟\\\"}}, \\\"sixDay\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"蛋白煎饼（蛋白3个+燕麦粉30g+香蕉半根）+ 无糖豆浆200ml\\\", \\\"noon\\\": \\\"烤鸡胸150g + 藜麦55g（干重）+ 烤茄子+洋葱200g + 橄榄油5g\\\", \\\"late\\\": \\\"虾仁100g + 冬瓜海带汤 + 凉拌黄瓜150g\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"核心 + 有氧耐力\\\", \\\"action\\\": [\\\"悬垂举腿 4组×12次\\\", \\\"健腹轮 3组×10次\\\", \\\"侧平板支撑 每侧3组×30秒\\\", \\\"登山跑 3组×30秒\\\"], \\\"aerobic\\\": \\\"户外跑步或椭圆机40分钟（心率维持在最大心率60-70%）\\\", \\\"duration\\\": \\\"60分钟\\\"}}, \\\"seven\\\": {\\\"diet\\\": {\\\"morning\\\": \\\"水煮蛋2个 + 全麦吐司1片 + 牛油果1/4个 + 黑咖啡\\\", \\\"noon\\\": \\\"三文鱼150g + 红薯140g（熟重）+ 西兰花+胡萝卜200g + 橄榄油5g\\\", \\\"late\\\": \\\"豆腐120g + 菠菜150g + 紫菜蛋花汤（少油）\\\"}, \\\"Motion\\\": {\\\"motionContent\\\": \\\"完全休息或轻度活动\\\", \\\"action\\\": [\\\"散步、瑜伽、拉伸\\\"], \\\"aerobic\\\": \\\"\\\", \\\"duration\\\": \\\"0-30分钟（自愿）\\\"}}}\"', '2026-04-05 16:24:55', '177', '80', '', '减脂', 1, 0);
