INSERT INTO `fitness_plan` VALUES (25, '{\"seven\": {\"diet\": {\"late\": \"豆腐100g + 菠菜150g + 番茄豆腐汤（无油）\", \"noon\": \"三文鱼100g（烤制少油）+ 红薯100g（熟重）+ 西兰花+胡萝卜150g + 柠檬汁调味\", \"morning\": \"水煮蛋1个 + 全麦吐司半片 + 牛油果1/8个\"}, \"Motion\": {\"action\": [\"散步15-20分钟（可选）\", \"深呼吸与冥想10分钟\"], \"aerobic\": \"\", \"duration\": \"0-20分钟（自愿，以舒适为原则）\", \"motionContent\": \"完全休息或极轻度活动\"}}, \"oneDay\": {\"diet\": {\"late\": \"清蒸鲈鱼100g + 凉拌菠菜150g + 小番茄5颗 + 柠檬汁调味\", \"noon\": \"去皮鸡胸肉120g + 糙米饭80g（熟重）+ 清炒西兰花200g + 橄榄油3g\", \"morning\": \"燕麦40g + 蛋白2个 + 全蛋1个 + 蓝莓50g + 无糖豆浆200ml\"}, \"Motion\": {\"action\": [\"靠墙静蹲 3组×30秒\", \"弹力带坐姿划船 3组×12次\", \"徒手深蹲（慢速控制）3组×10次\", \"站姿哑铃推举（轻重量）3组×12次\", \"猫牛式伸展 + 胸椎旋转 各2分钟\"], \"aerobic\": \"餐后快走20分钟（心率控制在最大心率50-60%，约90-105bpm）\", \"duration\": \"40分钟\", \"motionContent\": \"低强度全身激活训练（避免心率骤升）\"}}, \"sixDay\": {\"diet\": {\"late\": \"虾仁80g + 冬瓜海带汤 + 凉拌莴笋150g\", \"noon\": \"烤鸡胸100g + 藜麦40g（干重）+ 烤茄子+洋葱150g + 橄榄油3g\", \"morning\": \"蛋白煎饼（蛋白2个+燕麦粉20g）+ 无糖豆浆150ml\"}, \"Motion\": {\"action\": [\"瑜伽基础序列（猫牛、婴儿式、山式、战士I改良版）20分钟\", \"胸廓扩张呼吸练习 5分钟\"], \"aerobic\": \"水中步行或椭圆机25分钟（心率维持在90-105bpm）\", \"duration\": \"40分钟\", \"motionContent\": \"柔韧性 + 低强度有氧\"}}, \"towDay\": {\"diet\": {\"late\": \"豆腐120g + 海带冬瓜汤（无油）+ 凉拌黄瓜150g\", \"noon\": \"瘦牛肉100g（炖煮少油）+ 红薯100g（熟重）+ 清炒芥蓝200g + 蒜蓉橄榄油3g\", \"morning\": \"全麦吐司1片 + 水煮蛋1个 + 牛油果1/6个 + 黑咖啡（无糖无奶）\"}, \"Motion\": {\"action\": [\"弹力带高位下拉 3组×12次\", \"哑铃弯举（1-2kg）3组×15次\", \"坐姿肩部推举（轻重量）3组×12次\", \"腹式呼吸训练 5分钟\", \"肋间肌放松拉伸 5分钟\"], \"aerobic\": \"水中行走或固定自行车20分钟（阻力低，心率≤100bpm）\", \"duration\": \"35-40分钟\", \"motionContent\": \"上肢轻力量 + 呼吸训练\"}}, \"fiveDay\": {\"diet\": {\"late\": \"豆腐100g + 紫菜蛋花汤（少盐无油）+ 凉拌木耳100g\", \"noon\": \"瘦猪肉100g（清炒少油）+ 糙米饭80g（熟重）+ 白灼菜心200g + 蒜蓉橄榄油3g\", \"morning\": \"水煮蛋1个 + 全麦贝果半块 + 花生酱5g + 黑咖啡\"}, \"Motion\": {\"action\": [\"死虫式 3组×12次/侧\", \"鸟狗式 3组×10次/侧\", \"改良平板支撑（跪姿）3组×20-30秒\", \"侧卧抬腿（强化臀中肌）3组×15次/侧\"], \"aerobic\": \"固定自行车20分钟（轻松阻力，保持对话节奏）\", \"duration\": \"35分钟\", \"motionContent\": \"核心稳定性训练（避免仰卧起坐类动作）\"}}, \"fourDay\": {\"diet\": {\"late\": \"清蒸鳕鱼100g + 烤彩椒+西兰花150g + 南瓜80g（熟重）\", \"noon\": \"水浸金枪鱼100g + 全麦意面50g（干重）+ 西葫芦炒蘑菇150g + 橄榄油3g\", \"morning\": \"蛋白2个 + 燕麦30g + 苹果半个（小）\"}, \"Motion\": {\"action\": [\"椅子辅助弓步（自重）3组×8次/腿\", \"坐姿腿屈伸（无器械可用毛巾辅助）3组×12次\", \"臀桥（仰卧抬臀）3组×15次\", \"小腿提踵（扶墙）3组×15次\"], \"aerobic\": \"餐后散步25分钟（平地，匀速，心率≤100bpm）\", \"duration\": \"40分钟\", \"motionContent\": \"下肢轻负荷训练（避免大负重与屏气）\"}}, \"threeDay\": {\"diet\": {\"late\": \"虾仁80g + 芦笋150g + 紫甘蓝沙拉100g（无高脂酱料）\", \"noon\": \"去皮鸡腿肉100g（蒸）+ 荞麦面50g（干重）+ 清炒生菜200g + 香油2g\", \"morning\": \"无糖希腊酸奶100g + 奇亚籽5g + 草莓50g\"}, \"Motion\": {\"action\": [\"太极拳或八段锦 20分钟\", \"泡沫轴放松下肢与背部（避开胸腔区域）\", \"静态拉伸（肩、背、腿）每个动作30秒×2组\"], \"aerobic\": \"\", \"duration\": \"30分钟\", \"motionContent\": \"主动恢复日（重点：心肺温和刺激 + 放松）\"}}}', '2026-05-12 03:21:35', '175', '80', '心脏病', '减脂', 7, 1);
