INSERT INTO `fitness_plan` VALUES (32, '{\"seven\": {\"diet\": {\"late\": \"豆腐100g + 菠菜120g + 紫菜蛋花汤（少油少盐）\", \"noon\": \"三文鱼120g + 红薯120g（熟重）+ 西兰花+胡萝卜150g + 橄榄油5g\", \"morning\": \"水煮蛋1个 + 全麦吐司半片 + 牛油果1/8个 + 黑咖啡（无糖）\"}, \"Motion\": {\"action\": [\"深呼吸练习 + 温和拉伸\"], \"aerobic\": \"\", \"duration\": \"0-20分钟（自愿且经医生确认安全）\", \"motionContent\": \"完全休息或仅进行医嘱许可的轻度活动\"}}, \"oneDay\": {\"diet\": {\"late\": \"三文鱼100g + 菠菜沙拉（生菠菜150g + 小番茄5颗 + 黄瓜半根 + 油醋汁5ml）\", \"noon\": \"鸡胸肉130g + 糙米饭80g（熟重）+ 西兰花200g + 橄榄油5g\", \"morning\": \"燕麦40g + 蛋白2个 + 全蛋1个 + 蓝莓50g + 无糖豆浆200ml\"}, \"Motion\": {\"action\": [\"器械坐姿推胸 3组×10-12次\", \"哑铃肩推（轻重量）3组×12次\", \"高位下拉辅助推举 3组×12次\", \"绳索下压 2组×15次\", \"侧平举（轻重量）2组×15次\"], \"aerobic\": \"空腹低强度快走20分钟（心率控制在最大心率50-60%）\", \"duration\": \"45分钟\", \"motionContent\": \"低强度力量训练（上肢推：胸、肩、三头）\"}}, \"sixDay\": {\"diet\": {\"late\": \"虾仁80g + 冬瓜海带汤 + 凉拌黄瓜100g\", \"noon\": \"烤鸡胸120g + 藜麦50g（干重）+ 烤茄子+洋葱150g + 橄榄油5g\", \"morning\": \"蛋白煎饼（蛋白2个+燕麦粉20g+香蕉1/4根）+ 无糖豆浆150ml\"}, \"Motion\": {\"action\": [\"仰卧死虫式 3组×12次/侧\", \"鸟狗式 3组×10次/侧\", \"侧桥（屈膝）每侧2组×20秒\", \"猫牛式伸展 2组×10次\"], \"aerobic\": \"散步或水中行走30分钟（如医生允许）\", \"duration\": \"40分钟\", \"motionContent\": \"核心稳定性训练（避免屏气和高压动作）\"}}, \"towDay\": {\"diet\": {\"late\": \"虾仁100g + 芦笋150g + 藜麦40g（干重）\", \"noon\": \"瘦牛肉120g + 红薯120g（熟重）+ 混合蔬菜（生菜、彩椒）150g + 橄榄油5g\", \"morning\": \"全麦吐司1片 + 牛油果1/6个 + 水煮蛋1个 + 黑咖啡（无糖）\"}, \"Motion\": {\"action\": [\"器械腿举 3组×12-15次\", \"坐姿腿弯举 3组×15次\", \"靠墙静蹲 3组×30秒\", \"坐姿提踵 2组×20次\"], \"aerobic\": \"固定自行车低阻力骑���20分钟（心率≤110bpm）\", \"duration\": \"50分钟\", \"motionContent\": \"低强度下肢训练 + 医嘱许可下的有氧\"}}, \"fiveDay\": {\"diet\": {\"late\": \"鳕鱼100g + 芽菜沙拉100g + 小番茄+黄瓜 + 柠檬橄榄油汁\", \"noon\": \"瘦猪肉120g + 糙米饭80g（熟重）+ 芥蓝150g + 蒜蓉橄榄油5g\", \"morning\": \"全麦贝果半份 + 花生酱5g + 水煮蛋1个 + 黑咖啡（无糖）\"}, \"Motion\": {\"action\": [\"弹力带推拉 3组×15次\", \"靠墙俯卧撑 3组×力竭\", \"坐姿战绳轻摆 2组×30秒\", \"平板支撑（膝盖着地）2组×20秒\"], \"aerobic\": \"固定自行车或椭圆机20分钟（低阻力，心率≤110bpm）\", \"duration\": \"45分钟\", \"motionContent\": \"全身低强度功能性训练\"}}, \"fourDay\": {\"diet\": {\"late\": \"鸡胸肉100g + 烤彩椒+西兰花150g + 南瓜80g（熟重）\", \"noon\": \"水浸金枪鱼100g + 全麦意面50g（干重）+ 西葫芦炒蘑菇150g + 橄榄油5g\", \"morning\": \"燕麦30g + 蛋白2个 + 核桃5g + 苹果1/4个\"}, \"Motion\": {\"action\": [\"高位下拉（轻重量）3组×12次\", \"坐姿划船（器械）3组×12次\", \"反向飞鸟 2组×15次\", \"哑铃锤式弯举 2组×15次\"], \"aerobic\": \"空腹低强度快走20分钟（心率控制在最大心率50-60%）\", \"duration\": \"45分钟\", \"motionContent\": \"低强度上肢拉训练（背、二头）\"}}, \"threeDay\": {\"diet\": {\"late\": \"豆腐120g + 海带汤（少盐）+ 凉拌紫甘蓝100g\", \"noon\": \"去皮鸡腿肉120g + 荞麦面50g（干重）+ 青菜150g + 蒜蓉橄榄油5g\", \"morning\": \"希腊酸奶100g（无糖）+ 奇亚籽5g + 草莓50g + 蛋白粉半勺（加水）\"}, \"Motion\": {\"action\": [\"散步20分钟 + 泡沫轴轻柔放松 + 全身静态拉伸\"], \"aerobic\": \"\", \"duration\": \"30分钟\", \"motionContent\": \"主动恢复日（以医生建议为准）\"}}}', '2026-05-26 01:04:18', '175', '80', '心脏病', '减脂增肌', 346, 1);
INSERT INTO `fitness_plan` VALUES (33, '{\"seven\": {\"diet\": {\"late\": \"豆腐120g + 菠菜150g + 紫菜蛋花汤（少油）\", \"noon\": \"三文鱼150g + 红薯150g（熟重）+ 西兰花+胡萝卜200g + 橄榄油5g\", \"morning\": \"水煮蛋2个 + 全麦吐司1片 + 牛油果1/4个 + 黑咖啡\"}, \"Motion\": {\"action\": [\"散步、瑜伽、拉伸\"], \"aerobic\": \"\", \"duration\": \"0-30分钟（自愿）\", \"motionContent\": \"完全休息或轻度活动\"}}, \"oneDay\": {\"diet\": {\"late\": \"三文鱼130g + 菠菜沙拉（生菠菜150g + 小番茄5颗 + 黄瓜半根 + 油醋汁5ml）\", \"noon\": \"鸡胸肉160g + 糙米饭100g（熟重）+ 西兰花200g + 橄榄油5g\", \"morning\": \"燕麦50g + 蛋白3个 + 全蛋1个 + 蓝莓50g + 无糖杏仁奶200ml\"}, \"Motion\": {\"action\": [\"平板杠铃卧推 4组×8-10次\", \"哑铃肩推 4组×10次\", \"上斜哑铃卧推 3组×10-12次\", \"绳索下压 3组×12-15次\", \"侧平举 3组×15次\"], \"aerobic\": \"空腹低强度快走30分钟（可选）\", \"duration\": \"60-70分钟\", \"motionContent\": \"力量训练（上肢推：胸、肩、三头）\"}}, \"sixDay\": {\"diet\": {\"late\": \"虾仁110g + 冬瓜海带汤 + 凉拌黄瓜150g\", \"noon\": \"烤鸡胸160g + 藜麦60g（干重）+ 烤茄子+洋葱200g + 橄榄油5g\", \"morning\": \"蛋白煎饼（蛋白3个+燕麦粉30g+香蕉半根）+ 无糖豆浆200ml\"}, \"Motion\": {\"action\": [\"悬垂举腿 4组×12次\", \"健腹轮 3组×10次\", \"侧平板支撑 每侧3组×30秒\", \"登山跑 3组×30秒\"], \"aerobic\": \"户外跑步或椭圆机40分钟（心率维持在最大心率60-70%）\", \"duration\": \"60分钟\", \"motionContent\": \"核心 + 有氧耐力\"}}, \"towDay\": {\"diet\": {\"late\": \"虾仁130g + 芦笋200g + 藜麦50g（干重）\", \"noon\": \"瘦牛肉160g + 红薯150g（熟重）+ 混合蔬菜（生菜、彩椒、洋葱）200g + 橄榄油5g\", \"morning\": \"全麦吐司2片 + 牛油果1/4个 + 水煮蛋2个 + 黑咖啡\"}, \"Motion\": {\"action\": [\"杠铃深蹲 4组×8-10次\", \"罗马尼亚硬拉 4组×10次\", \"保加利亚分腿蹲 3组×10次/腿\", \"腿弯举 3组×12-15次\", \"提踵 4组×15-20次\"], \"aerobic\": \"高强度间歇训练（HIIT）20分钟（如：30秒冲刺+60秒慢走，重复8轮）\", \"duration\": \"70-80分钟\", \"motionContent\": \"力量训练（下肢：股四头肌、腘绳肌、臀）+ 有氧\"}}, \"fiveDay\": {\"diet\": {\"late\": \"鳕鱼130g + 芽菜沙拉150g + 小番茄+黄瓜 + 柠檬橄榄油汁\", \"noon\": \"瘦猪肉160g + 糙米饭100g（熟重）+ 芥蓝200g + 蒜蓉橄榄油5g\", \"morning\": \"全麦贝果1个 + 花生酱10g + 水煮蛋2个 + 黑咖啡\"}, \"Motion\": {\"action\": [\"壶铃摇摆 4组×20次\", \"战绳 3组×30秒\", \"跳箱 3组×10次\", \"农夫行走 3组×30米\", \"平板支撑 3组×45秒\"], \"aerobic\": \"中等强度稳态有氧（如跑步机快走/慢跑）30分钟\", \"duration\": \"60分钟\", \"motionContent\": \"全身功能性训练 + 有氧\"}}, \"fourDay\": {\"diet\": {\"late\": \"鸡胸肉130g + 烤彩椒+西兰花200g + 南瓜100g（熟重）\", \"noon\": \"金枪鱼罐头（水浸）130g + 全麦意面60g（干重）+ 西葫芦炒蘑菇150g + 橄榄油5g\", \"morning\": \"燕麦40g + 蛋白3个 + 核桃10g + 苹果半个\"}, \"Motion\": {\"action\": [\"引体向上（辅助）4组×力竭\", \"杠铃划船 4组×8-10次\", \"高位下拉 3组×10-12次\", \"坐姿划船 3组×12次\", \"哑铃弯举 3组×12-15次\"], \"aerobic\": \"空腹低强度快走30分钟（可选）\", \"duration\": \"60-70分钟\", \"motionContent\": \"力量训练（上肢拉：背、二头）\"}}, \"threeDay\": {\"diet\": {\"late\": \"豆腐150g + 海带汤 + 紫甘蓝沙拉100g + 杏仁10颗\", \"noon\": \"鸡腿肉（去皮）160g + 荞麦面60g（干重）+ 青菜200g + 蒜蓉橄榄油5g\", \"morning\": \"希腊酸奶150g（无糖）+ 奇亚籽10g + 草莓50g + 蛋白粉1勺（加水）\"}, \"Motion\": {\"action\": [\"快走或骑行40分钟 + 泡沫轴放松 + 拉伸\"], \"aerobic\": \"\", \"duration\": \"45-50分钟\", \"motionContent\": \"主动恢复日\"}}}', '2026-05-26 04:01:33', '175', '80', '无', '减脂增肌', 349, 0);
